/* ---------- Cost Scenarios ---------- */
function costScenarios(city, mult, cd) {
  const bp = pricingModel.basePriceByService;
  const rnd = pricingModel.roundTo || 25;

  const budgetTotal = roundTo(Math.round(bp.water_heater.priceByType.tank_50_gas * mult), rnd);
  const midTotal = roundTo(Math.round(bp.bathroom_rough_in.priceByScope.full_bath * mult), rnd);
  const premTotal = roundTo(Math.round(bp.repipe.priceByMaterial.pex * mult * 1.15), rnd);

  const budgetBody = `${cd.waterHeaterCulturePara.split(". ")[0]}. ${cd.hardnessAndSourcePara.split(". ")[0]}.`;
  const midBody = `${cd.pipeMaterialByEraPara.split(". ")[0]}. ${cd.permitAndLicensePara.split(". ")[0]}.`;
  const premBody = `${cd.commonIssuesPara.split(". ")[0]}. ${cd.sewerInfrastructurePara.split(". ")[0]}.`;

  function card(label, title, total, body, color) {
    return `
<div class="fp-scenario-card" style="border-top:4px solid ${color};">
<h3>${label}</h3>
<p class="fp-scenario-material">${title}</p>
<p class="fp-scenario-total">${fmtD(total)}</p>
<p class="fp-scenario-detail">${body}</p>
</div>`;
  }

  return `
<section class="section fp-section">
<h2>${city} Plumbing Project Scenarios</h2>
<div class="fp-scenario-grid">
${card("Budget", `50-gallon gas tank water heater swap`, budgetTotal, budgetBody, "#22c55e")}
${card("Mid-range", `Full bathroom rough-in, ${city}`, midTotal, midBody, "#3b82f6")}
${card("Premium", `Whole-house PEX repipe, ${city}`, premTotal, premBody, "#8b5cf6")}
</div>
</section>`;
}

